import React, { useState } from "react";
import dayjs from "dayjs";
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  Tooltip,
  Legend,
} from "chart.js";
import { Bar } from "react-chartjs-2";

ChartJS.register(CategoryScale, LinearScale, BarElement, Tooltip, Legend);

function Dashboard() {
  const adminProfile = {
    name: "Admin",
    lastUpdated: new Date(),
  };

  const summaryCards = {
    totalUsers: 1250,
    totalLeads: 842,
    totalRevenue: 2450000,
    totalSupportTickets: 128,
  };

  /* ================= FILTER STATES ================= */

  const currentYear = new Date().getFullYear();
  const [selectedYear, setSelectedYear] = useState(currentYear);
  const [selectedMonth, setSelectedMonth] = useState("all");

  /* ================= DUMMY DATA ================= */

  const dummyData = {
    2025: {
      1: { clients: 30, payments: 300000, leads: 100, approved: 80, duplicate: 10 },
      2: { clients: 40, payments: 450000, leads: 120, approved: 90, duplicate: 12 },
      3: { clients: 35, payments: 380000, leads: 110, approved: 85, duplicate: 9 },
    },
    2026: {
      1: { clients: 50, payments: 500000, leads: 140, approved: 110, duplicate: 15 },
      2: { clients: 60, payments: 620000, leads: 160, approved: 130, duplicate: 18 },
      3: { clients: 55, payments: 580000, leads: 150, approved: 120, duplicate: 14 },
      4: { clients: 70, payments: 720000, leads: 180, approved: 145, duplicate: 20 },
      5: { clients: 65, payments: 690000, leads: 170, approved: 140, duplicate: 17 },
      6: { clients: 80, payments: 810000, leads: 200, approved: 160, duplicate: 22 },
    },
  };

  const yearData = dummyData[selectedYear] || {};

  const months = Object.keys(yearData);

  const filteredMonths =
    selectedMonth === "all" ? months : months.filter((m) => m === selectedMonth);

  const labels = filteredMonths.map((m) =>
    dayjs(`${selectedYear}-${m}-01`).format("MMM YYYY")
  );

  const clientData = filteredMonths.map((m) => yearData[m].clients);
  const paymentData = filteredMonths.map((m) => yearData[m].payments);
  const commissionData = paymentData.map((amt) =>
    Number(((amt * 10) / 100).toFixed(0))
  );

  const totalLeads = filteredMonths.map((m) => yearData[m].leads);
  const approvedLeads = filteredMonths.map((m) => yearData[m].approved);
  const duplicateLeads = filteredMonths.map((m) => yearData[m].duplicate);

  /* ================= PAYMENTS CHART ================= */

  const paymentsChartData = {
    labels,
    datasets: [
      {
        label: "Clients Converted",
        data: clientData,
        backgroundColor: "#0d6efd65",
        borderRadius: 8,
      },
      {
        label: "Payments (₹)",
        data: paymentData,
        backgroundColor: "#19875475",
        borderRadius: 8,
        yAxisID: "yAmount",
      },
      {
        label: "Commission (10%)",
        data: commissionData,
        backgroundColor: "#ffc10775",
        borderRadius: 8,
        yAxisID: "yAmount",
      },
    ],
  };

  const paymentsChartOptions = {
    responsive: true,
    maintainAspectRatio: false,
    plugins: {
      legend: { position: "top" },
      title: {
        display: true,
        text: `Payments Overview (${selectedYear})`,
      },
    },
    scales: {
      y: {
        beginAtZero: true,
        title: { display: true, text: "Clients" },
      },
      yAmount: {
        position: "right",
        beginAtZero: true,
        grid: { drawOnChartArea: false },
        ticks: {
          callback: (value) => `₹${(value / 1000).toFixed(0)}k`,
        },
      },
    },
  };

  /* ================= LEAD CHART ================= */

  const leadChartData = {
    labels,
    datasets: [
      {
        label: "Total Leads",
        data: totalLeads,
        backgroundColor: "#0d6efd65",
        borderRadius: 8,
      },
      {
        label: "Approved Leads",
        data: approvedLeads,
        backgroundColor: "#19875475",
        borderRadius: 8,
      },
      {
        label: "Duplicate Leads",
        data: duplicateLeads,
        backgroundColor: "#dc354575",
        borderRadius: 8,
      },
    ],
  };

  const leadChartOptions = {
    responsive: true,
    maintainAspectRatio: false,
    plugins: {
      legend: { position: "top" },
      title: {
        display: true,
        text: `Lead Status (${selectedYear})`,
      },
    },
    scales: {
      y: {
        beginAtZero: true,
      },
    },
  };

  return (
    <div className="container py-3">
      {/* Header */}
      <h4 className="fw-bold fs-3">Welcome, {adminProfile.name}</h4>
      <small>
        Last Updated:{" "}
        {dayjs(adminProfile.lastUpdated).format("DD MMM YYYY, hh:mm A")}
      </small>

      {/* Summary Cards */}
      <div className="row g-3 pt-3">
        <div className="col-md-3 col-6">
          <div className="p-3 rounded bg-body border-start border-5 border-primary border-opacity-50">
            <small>Total Users</small>
            <h5>{summaryCards.totalUsers}</h5>
          </div>
        </div>
        <div className="col-md-3 col-6">
          <div className="p-3 rounded bg-body border-start border-5 border-success border-opacity-50">
            <small>Total Leads</small>
            <h5>{summaryCards.totalLeads}</h5>
          </div>
        </div>
        <div className="col-md-3 col-6">
          <div className="p-3 rounded bg-body border-start border-5 border-warning border-opacity-50">
            <small>Total Revenue</small>
            <h5>₹{summaryCards.totalRevenue.toLocaleString("en-IN")}</h5>
          </div>
        </div>
        <div className="col-md-3 col-6">
          <div className="p-3 rounded bg-body border-start border-5 border-danger border-opacity-50">
            <small>Support Tickets</small>
            <h5>{summaryCards.totalSupportTickets}</h5>
          </div>
        </div>
      </div>

      {/* Filters */}
      <div className="row pt-4 g-3">
        <div className="col-md-3 col-6">
          <select
            className="form-select"
            value={selectedYear}
            onChange={(e) => setSelectedYear(Number(e.target.value))}
          >
            {Object.keys(dummyData).map((year) => (
              <option key={year} value={year}>
                {year}
              </option>
            ))}
          </select>
        </div>

        <div className="col-md-3 col-6">
          <select
            className="form-select"
            value={selectedMonth}
            onChange={(e) => setSelectedMonth(e.target.value)}
          >
            <option value="all">All Months</option>
            {months.map((month) => (
              <option key={month} value={month}>
                {dayjs(`${selectedYear}-${month}-01`).format("MMMM")}
              </option>
            ))}
          </select>
        </div>
      </div>

      {/* Charts */}
      <div className="row pt-4 g-4">
        <div className="col-lg-4 col-12">
          <div className="border rounded p-3 bg-body" style={{ height: "350px" }}>
            <Bar data={leadChartData} options={leadChartOptions} />
          </div>
        </div>

        <div className="col-lg-8 col-12">
          <div className="border rounded p-3 bg-body" style={{ height: "350px" }}>
            <Bar data={paymentsChartData} options={paymentsChartOptions} />
          </div>
        </div>
      </div>
    </div>
  );
}

export default Dashboard;
